import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Save, Calendar, ShoppingBag, Hash, Receipt, CreditCard, User, Lock, Wallet } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback'; // Importando o novo Modal
import '../styles/Lancamento.css';

const Lancamento = () => {
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]); 
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  // Estado para controlar o Modal de Feedback
  const [modal, setModal] = useState({ 
    isOpen: false, 
    type: 'success', 
    title: '', 
    message: '' 
  });

  const formasPagamento = ["Boleto", "Crédito", "Débito", "Dinheiro", "Pix", "Transferência"].sort();

  const [form, setForm] = useState({
    descricao: '', valor_total: '', loja: '', pedido: '', 
    nota_fiscal: '', user_id: '', forma_pagamento: 'Crédito',
    num_parcelas: 1, cartao: '', data_compra: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    verificarAcessoEBucarDados();
  }, []);

  async function verificarAcessoEBucarDados() {
    try {
      setFetching(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfil } = await supabase.from('profiles').select('tipo_usuario').eq('id', user.id).single();
      setPerfilLogado(perfil);

      if (perfil?.tipo_usuario === 'proprietario') {
        const { data: dC } = await supabase.from('cartoes').select('id, nome').order('nome');
        const { data: dU } = await supabase.from('profiles').select('id, nome').order('nome');
        setCartoes(dC || []);
        setUsuarios(dU || []);
      }
    } finally {
      setFetching(false);
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const isCredito = form.forma_pagamento === 'Crédito';
    const numP = isCredito ? parseInt(form.num_parcelas) : 1;

    // Validação básica antes de enviar
    if (parseFloat(form.valor_total) <= 0) {
      setModal({
        isOpen: true,
        type: 'warning',
        title: 'Atenção',
        message: 'O valor total deve ser maior que zero.'
      });
      setLoading(false);
      return;
    }

    const { error } = await supabase.from('compras').insert([{
      ...form,
      valor_total: parseFloat(form.valor_total),
      num_parcelas: numP,
      parcelado: numP > 1,
      cartao: isCredito ? form.cartao : 'À Vista'
    }]);

    if (!error) {
      setModal({
        isOpen: true,
        type: 'success',
        title: 'Sucesso!',
        message: 'Gasto registrado corretamente na base de dados.'
      });
      setForm({ ...form, descricao: '', valor_total: '', loja: '', pedido: '', nota_fiscal: '', num_parcelas: 1, cartao: '' });
    } else {
      setModal({
        isOpen: true,
        type: 'error',
        title: 'Erro ao salvar',
        message: error.message
      });
    }
    setLoading(false);
  };

  if (fetching) return <div style={{ padding: '40px', textAlign: 'center' }}>Carregando permissões...</div>;
  if (perfilLogado?.tipo_usuario !== 'proprietario') {
    return (
      <div className="access-denied" style={{ textAlign: 'center', marginTop: '100px', padding: '20px' }}>
        <div style={{ background: '#fff1f2', width: '80px', height: '80px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
          <Lock size={40} color="#f43f5e" />
        </div>
        <h2 style={{ color: '#0f172a' }}>Acesso Restrito</h2>
        <p style={{ color: '#64748b' }}>Apenas administradores podem realizar lançamentos.</p>
      </div>
    );
  }

  return (
    <div className="lancamento-container fade-in">
      <header className="lancamento-header">
        <h2>Novo Lançamento</h2>
        <p>Registre um gasto para a unidade</p>
      </header>
      
      <div className="card lancamento-card">
        <form onSubmit={handleSubmit}>
          
          <div className="form-row-top">
            <div className="input-group">
              <label className="input-label"><Calendar size={14} /> Data</label>
              <input type="date" className="form-control" value={form.data_compra} required onChange={e => setForm({...form, data_compra: e.target.value})} />
            </div>
            <div className="input-group">
              <label className="input-label"><ShoppingBag size={14} /> Loja</label>
              <input placeholder="Ex: Amazon" className="form-control" value={form.loja} onChange={e => setForm({...form, loja: e.target.value})} />
            </div>
            <div className="input-group">
              <label className="input-label"><User size={14} /> Responsável</label>
              <select className="form-control" required value={form.user_id} onChange={e => setForm({...form, user_id: e.target.value})}>
                <option value="">Quem comprou?</option>
                {usuarios.map(u => <option key={u.id} value={u.id}>{u.nome}</option>)}
              </select>
            </div>
          </div>

          <div className="input-group" style={{ marginBottom: '20px' }}>
            <label className="input-label">Descrição</label>
            <input placeholder="O que foi comprado?" className="form-control" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} />
          </div>

          <div className="form-row-top">
            <div className="input-group">
              <label className="input-label"><Hash size={14} /> Pedido</label>
              <input placeholder="Opcional" className="form-control" value={form.pedido} onChange={e => setForm({...form, pedido: e.target.value})} />
            </div>
            <div className="input-group">
              <label className="input-label"><Receipt size={14} /> Nota Fiscal</label>
              <input placeholder="Opcional" className="form-control" value={form.nota_fiscal} onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
            </div>
          </div>

          <div className="payment-row">
            <div className="input-group flex-item-valor">
              <label className="input-label">Valor Total</label>
              <div className="input-with-prefix">
                <span className="prefix-icon">R$</span>
                <input type="number" step="0.01" placeholder="0,00" className="form-control" required value={form.valor_total} onChange={e => setForm({...form, valor_total: e.target.value})} />
              </div>
            </div>

            <div className="input-group flex-item-forma">
              <label className="input-label"><Wallet size={14} /> Pagamento</label>
              <select className="form-control select-pagamento" value={form.forma_pagamento} onChange={e => setForm({...form, forma_pagamento: e.target.value})}>
                {formasPagamento.map(f => <option key={f} value={f}>{f}</option>)}
              </select>
            </div>

            {form.forma_pagamento === 'Crédito' && (
              <>
                <div className="input-group flex-item-cartao animate-in">
                  <label className="input-label"><CreditCard size={14} /> Cartão</label>
                  <select className="form-control" required value={form.cartao} onChange={e => setForm({...form, cartao: e.target.value})}>
                    <option value="">Qual?</option>
                    {cartoes.map(c => <option key={c.id} value={c.nome}>{c.nome}</option>)}
                  </select>
                </div>
                <div className="input-group flex-item-parcela animate-in">
                  <label className="input-label">Parc.</label>
                  <input type="number" min="1" className="form-control" required value={form.num_parcelas} onChange={e => setForm({...form, num_parcelas: e.target.value})} style={{ textAlign: 'center', fontWeight: '800' }} />
                </div>
              </>
            )}
          </div>

          <button type="submit" className="btn-submit" disabled={loading}>
            {loading ? 'Salvando...' : <><Save size={20} style={{ marginRight: '10px' }} /> Confirmar Lançamento</>}
          </button>
        </form>
      </div>

      {/* Componente Modal adicionado ao final */}
      <ModalFeedback 
        isOpen={modal.isOpen}
        type={modal.type}
        title={modal.title}
        message={modal.message}
        onClose={() => setModal({ ...modal, isOpen: false })}
      />
    </div>
  );
};

export default Lancamento;
